import{_ as e,o as t,c as s,ai as r}from"./chunks/framework.ampVZV4B.js";const p=JSON.parse('{"title":"集合框架（Collections）深度解析","description":"","frontmatter":{},"headers":[],"relativePath":"java/collections.md","filePath":"java/collections.md"}'),n={name:"java/collections.md"};function a(c,o,d,i,l,g){return t(),s("div",null,[...o[0]||(o[0]=[r('<h1 id="集合框架-collections-深度解析" tabindex="-1">集合框架（Collections）深度解析 <a class="header-anchor" href="#集合框架-collections-深度解析" aria-label="Permalink to “集合框架（Collections）深度解析”">​</a></h1><h2 id="本模块面试重点" tabindex="-1">本模块面试重点 <a class="header-anchor" href="#本模块面试重点" aria-label="Permalink to “本模块面试重点”">​</a></h2><ul><li><strong>集合体系结构</strong>：熟悉 <code>Collection</code> / <code>Map</code> 两大体系，知道 <code>List</code>、<code>Set</code>、<code>Map</code> 及它们常见实现类的大致特点和使用场景。</li><li><strong>常见实现类对比</strong>：<code>ArrayList</code> vs <code>LinkedList</code>、<code>HashMap</code> vs <code>Hashtable</code> vs <code>ConcurrentHashMap</code>，增删改查的时间复杂度和线程安全差异。</li><li><strong>典型坑点</strong>：<code>HashMap</code> 扩容/负载因子、遍历时修改集合导致的 <code>ConcurrentModificationException</code>、<code>Arrays.asList</code> 的不可变列表等。</li></ul><hr><h3 id="❓-面试官-java-集合框架有哪些顶层接口-你能画一下大概的结构图吗" tabindex="-1">❓ 面试官：Java 集合框架有哪些顶层接口？你能画一下大概的结构图吗？ <a class="header-anchor" href="#❓-面试官-java-集合框架有哪些顶层接口-你能画一下大概的结构图吗" aria-label="Permalink to “❓ 面试官：Java 集合框架有哪些顶层接口？你能画一下大概的结构图吗？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Java 集合框架主要分为两大派系：<strong><code>Collection</code>（单列集合）</strong> 和 <strong><code>Map</code>（双列键值对集合）</strong>。它们之下又派生出了 <code>List</code>、<code>Set</code> 和具体的 <code>HashMap</code> 等实现类。</p><p><strong>📝 核心脉络梳理：</strong></p><ol><li><strong>Collection（单列存取）</strong><ul><li><strong>List</strong>：有序、可重复、有索引。（代表：<code>ArrayList</code>、<code>LinkedList</code>）</li><li><strong>Set</strong>：无序、不可重复、无索引。（代表：<code>HashSet</code>、<code>TreeSet</code>）</li></ul></li><li><strong>Map（键值对存取）</strong><ul><li>存储 <code>Key-Value</code>，其中 Key 不可重复，Value 可重复。（代表：<code>HashMap</code>、<code>TreeMap</code>、<code>ConcurrentHashMap</code>）</li></ul></li></ol><hr><h3 id="❓-面试官-arraylist-和-linkedlist-有什么区别-平时开发中怎么选" tabindex="-1">❓ 面试官：ArrayList 和 LinkedList 有什么区别？平时开发中怎么选？ <a class="header-anchor" href="#❓-面试官-arraylist-和-linkedlist-有什么区别-平时开发中怎么选" aria-label="Permalink to “❓ 面试官：ArrayList 和 LinkedList 有什么区别？平时开发中怎么选？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong><code>ArrayList</code> 底层是<strong>动态数组</strong>，适合<strong>多读少写（或尾部追加）</strong>的场景；<code>LinkedList</code> 底层是<strong>双向链表</strong>，适合<strong>频繁在头部或中间进行插入/删除</strong>的场景。实际开发中，<code>99%</code> 的情况都用 <code>ArrayList</code>。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>数据结构</strong>： <ul><li><code>ArrayList</code>：一块连续的内存空间。支持通过下标 <code>O(1)</code> 极速随机访问。但如果要在中间插入或删除元素，需要移动后面所有的元素，时间复杂度 <code>O(N)</code>。</li><li><code>LinkedList</code>：内存不连续，靠指针连接。不支持随机访问，查第 N 个元素必须从头遍历 <code>O(N)</code>。但在已知节点位置的情况下，插入和删除只需修改指针，非常快。</li></ul></li><li><strong>空间占用</strong>： <ul><li><code>ArrayList</code> 会预留一定的容量空间（尾部可能有空闲），但总体紧凑。</li><li><code>LinkedList</code> 每个节点都要额外存储两个指针（前驱和后继），消耗内存更大。</li></ul></li></ol><p><strong>🌟 面试加分项（实战坑点）：</strong> 面试官常追问：“你说 LinkedList 插入快，那如果我在末尾追加 1 万个元素，谁快？” <strong>绝杀回答</strong>： &quot;依然是 <strong>ArrayList 快！</strong> 很多人以为 LinkedList 插入一定快，其实是误区。LinkedList 每次 <code>add</code> 都要去堆内存里 <code>new</code> 一个 <code>Node</code> 对象，海量数据下会触发频繁的垃圾回收（GC），非常慢。而 <code>ArrayList</code> 只要没有触发扩容，尾部追加只是简单地给数组赋值，极其迅速。即使触发扩容（系统级的 <code>System.arraycopy</code>），整体性能依然秒杀 LinkedList。&quot;</p><hr><h3 id="❓-面试官-能详细讲讲-hashmap-的底层原理吗-jdk-8-之后的结构-【中高级】" tabindex="-1">❓ 面试官：能详细讲讲 HashMap 的底层原理吗？（JDK 8 之后的结构）【中高级】 <a class="header-anchor" href="#❓-面试官-能详细讲讲-hashmap-的底层原理吗-jdk-8-之后的结构-【中高级】" aria-label="Permalink to “❓ 面试官：能详细讲讲 HashMap 的底层原理吗？（JDK 8 之后的结构）【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> JDK 8 中，<code>HashMap</code> 的底层数据结构是 <strong>“数组 + 链表 + 红黑树”</strong>。这种设计既保证了极快的通过哈希计算找桶的速度，又通过红黑树解决了极端情况下哈希冲突导致的链表过长、查询变慢的问题。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>put(Key, Value) 核心流程</strong>： <ul><li>第一步：对 Key 调用 <code>hashCode()</code>，并经过一次扰动函数（高低 16 位异或），算出最终的 <code>hash</code> 值。</li><li>第二步：根据 <code>(n - 1) &amp; hash</code> 算出在数组中的索引位置。</li><li>第三步：如果该位置为空，直接存入。</li><li>第四步：如果发生哈希冲突（该位置已经有元素了），则用 <code>equals()</code> 判断 Key 是否一样。一样就覆盖 Value；不一样就在此节点后挂一个新节点（尾插法）。</li><li>第五步（树化）：<strong>如果当前链表长度大于等于 8，且数组总长度大于等于 64</strong>，就会把链表转化为<strong>红黑树</strong>，把 <code>O(N)</code> 的查询时间优化为 <code>O(log N)</code>。</li></ul></li><li><strong>扩容机制（Resize）</strong>： <ul><li>默认初始容量是 16，加载因子是 0.75。</li><li>当 <code>size &gt; 16 * 0.75 = 12</code> 时，触发扩容，数组容量<strong>翻倍</strong>（变成 32）。</li><li>扩容时极其巧妙：因为容量是 2 的幂次方，原来在链表上的元素重新计算位置时，只有两种结果：<strong>要么留在原位置，要么移动到（原位置 + 旧容量）的位置</strong>。</li></ul></li></ol><p><strong>🌟 面试加分项（连环追问）：</strong></p><ul><li><strong>问</strong>：为什么加载因子是 0.75 而不是 1 或 0.5？ <strong>答</strong>：这是时间和空间的折中。如果是 1，空间利用率高，但哈希冲突极其严重，链表会很长导致查询极慢；如果是 0.5，冲突少了，但内存浪费一半，且频繁触发扩容影响性能。0.75 是经过泊松分布概率计算得出的最优解。</li><li><strong>问</strong>：为什么链表转红黑树的阈值是 8？ <strong>答</strong>：根据泊松分布，在加载因子为 0.75 的理想哈希情况下，一个桶里挂 8 个节点的概率不到千万分之一。如果真的到了 8，说明哈希算法极差或者遭遇了恶意的哈希碰撞攻击，这时候才逼不得已转为红黑树保命（因为红黑树每个节点占空间比普通节点大一倍）。</li></ul><hr><h3 id="❓-面试官-hashmap-是线程安全的吗-多线程下会出什么问题-应该用什么代替-【中级】" tabindex="-1">❓ 面试官：HashMap 是线程安全的吗？多线程下会出什么问题？应该用什么代替？【中级】 <a class="header-anchor" href="#❓-面试官-hashmap-是线程安全的吗-多线程下会出什么问题-应该用什么代替-【中级】" aria-label="Permalink to “❓ 面试官：HashMap 是线程安全的吗？多线程下会出什么问题？应该用什么代替？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong><code>HashMap</code> 是<strong>绝对线程不安全的</strong>。在多线程并发 <code>put</code> 时，会导致<strong>数据覆盖丢失</strong>；如果是 JDK 7 版本，还会引发<strong>死循环（环形链表）</strong>导致 CPU 100%。必须用 <strong><code>ConcurrentHashMap</code></strong> 来代替。</p><p><strong>📝 ConcurrentHashMap 怎么保证线程安全的？</strong></p><ul><li><strong>JDK 7</strong>：采用了 <strong>“分段锁（Segment）”</strong> 机制。把整个大数组切分成 16 个小数组（Segment）。每次加锁只锁一个小数组，其他小数组的读写不受影响。</li><li><strong>JDK 8 终极优化</strong>： 摒弃了臃肿的分段锁，直接采用和 HashMap 一样的 <strong>“数组+链表+红黑树”</strong> 结构。 线程安全靠的是 <strong><code>CAS</code>（乐观锁） + <code>synchronized</code>（悲观锁）</strong>。 在 <code>put</code> 时： <ol><li>如果发现该桶的位置是空的，直接使用无锁的 <code>CAS</code> 操作尝试把新节点塞进去。</li><li>如果发现桶里已经有元素了发生冲突，只使用 <code>synchronized</code> <strong>锁住这一个头节点（链表首节点或树根）</strong>。锁的粒度变得极其细小，并发度达到了理论最大值（有多少个桶，就允许多少个线程同时并发写）。</li></ol></li></ul>',30)])])}const u=e(n,[["render",a]]);export{p as __pageData,u as default};
